SELECT project_name
FROM projects
WHERE project_id = 1;

SELECT AVG(budget) AS average_budget
FROM projects
WHERE status = 'active';

SELECT COUNT(*) 
FROM user_project_roles 
WHERE user_id = 1;

SELECT DISTINCT p.project_name, p.budget
FROM projects p
JOIN models m ON p.project_id = m.project_id;
